@frr_config_router_ospf_instanceid.group(cls=FRR_AbbreviationGroup, name='compatible',)
def frr_config_router_ospf_instanceid_compatible(compatible_='compatible'):
    """OSPF compatibility list"""
    global COMMON_DATA_MAP
    #ctx = click.get_current_context()
    #config_db = ValidatedConfigDBConnector(db.cfgdb)
    
    data_gen = {}
    name = frr_config_router_ospf_instanceid_compatible.name
    
    if 'OSPF_NODE|compatible' not in COMMON_DATA_MAP:
        COMMON_DATA_MAP['OSPF_NODE|compatible'] = {}

    for key, val in data_gen.items():
        if key.islower() and key in COMMON_DATA_MAP['OSPF_NODE|compatible']:
            key = key.upper()
        COMMON_DATA_MAP['OSPF_NODE|compatible'][key] = val
    
    #######################
    key_store = []
    global PREFIX_TMP
    for k, v in COMMON_DATA_MAP['OSPF_NODE|compatible'].items():
        if k.islower() and k != v:
            key_store.append(k)
        if k != v or '_NODE' not in v:
            key_store.append(v)
    key_store.insert(0, 'compatible')
    previous_key = key_store[:-1]
    if PREFIX_TMP and 'OSPF_NODE' not in BASE_NODE:
        pre_key = PREFIX_TMP.split('|')[-1]
        if key_store[0].startswith(pre_key):
            if '|' not in PREFIX_TMP:
                PREFIX_TMP = PREFIX_TMP.replace(f'{pre_key}', '')
            else:
                PREFIX_TMP = PREFIX_TMP.replace(f'|{pre_key}', '')
        if PREFIX_TMP != '' and key_store[0] not in PREFIX_TMP:
            key_store[0] = f'{PREFIX_TMP}|{key_store[0]}'
            if len(previous_key) == 0:
                previous_key = [PREFIX_TMP]
            else:
                previous_key[0] = f'{PREFIX_TMP}|{previous_key[0]}'
        if PREFIX_TMP.endswith(f'|{key_store[0]}'):
            key_store[0] = PREFIX_TMP
    
    COMMON_DATA_MAP['OSPF_NODE'] = tuple(key_store)
    PREFIX_TMP = '|'.join(key_store)

    pass


