def frr_config_router_ospf_instanceid_vrf_distance_ospf_external(distance_for_external_routes, external_='external'):
    """External routes"""
    global COMMON_DATA_MAP
    #ctx = click.get_current_context()
    #config_db = ValidatedConfigDBConnector(db.cfgdb)
    
    data_gen = {}
    name = frr_config_router_ospf_instanceid_vrf_distance_ospf_external.name
    data_gen['external'] = external_='external'
    data_gen['DISTANCE_FOR_EXTERNAL_ROUTES'] = distance_for_external_routes
    
    if 'OSPF_NODE|distance_ospf' not in COMMON_DATA_MAP:
        COMMON_DATA_MAP['OSPF_NODE|distance_ospf'] = {}

    for key, val in data_gen.items():
        if key.islower() and key in COMMON_DATA_MAP['OSPF_NODE|distance_ospf']:
            key = key.upper()
        COMMON_DATA_MAP['OSPF_NODE|distance_ospf'][key] = val
    
    #######################
    key_store = []
    global PREFIX_TMP
    for k, v in COMMON_DATA_MAP['OSPF_NODE|distance_ospf'].items():
        if k.islower() and k != v:
            key_store.append(k)
        if k != v or '_NODE' not in v:
            key_store.append(v)
    key_store.insert(0, 'distance_ospf')
    previous_key = key_store[:-1]
    if PREFIX_TMP and 'OSPF_NODE' not in BASE_NODE:
        pre_key = PREFIX_TMP.split('|')[-1]
        if key_store[0].startswith(pre_key):
            if '|' not in PREFIX_TMP:
                PREFIX_TMP = PREFIX_TMP.replace(f'{pre_key}', '')
            else:
                PREFIX_TMP = PREFIX_TMP.replace(f'|{pre_key}', '')
        if PREFIX_TMP != '' and key_store[0] not in PREFIX_TMP:
            key_store[0] = f'{PREFIX_TMP}|{key_store[0]}'
            if len(previous_key) == 0:
                previous_key = [PREFIX_TMP]
            else:
                previous_key[0] = f'{PREFIX_TMP}|{previous_key[0]}'
        if PREFIX_TMP.endswith(f'|{key_store[0]}'):
            key_store[0] = PREFIX_TMP
    
    COMMON_DATA_MAP['OSPF_NODE'] = tuple(key_store)
    PREFIX_TMP = '|'.join(key_store)

    pass


