@frr_config_router_ospf_vrf_area_areachoicecase_filterlist.group(cls=FRR_AbbreviationGroup, name='prefix',)
@click.argument('name_of_an_ip', metavar='PREFIXLIST_NAME', required=True, type=FRR_TYPE('PREFIXLIST_NAME'))
def frr_config_router_ospf_vrf_area_areachoicecase_filterlist_prefix(name_of_an_ip, filterlist_prefix_='filter-list_prefix'):
    """"""
    global COMMON_DATA_MAP
    #ctx = click.get_current_context()
    #config_db = ValidatedConfigDBConnector(db.cfgdb)
    
    data_gen = {}
    name = frr_config_router_ospf_vrf_area_areachoicecase_filterlist_prefix.name
    data_gen['filter-list_prefix'] = filterlist_prefix_='filter-list_prefix'
    data_gen['NAME_OF_AN_IP'] = name_of_an_ip
    
    if 'OSPF_NODE|area' not in COMMON_DATA_MAP:
        COMMON_DATA_MAP['OSPF_NODE|area'] = {}

    for key, val in data_gen.items():
        if key.islower() and key in COMMON_DATA_MAP['OSPF_NODE|area']:
            key = key.upper()
        COMMON_DATA_MAP['OSPF_NODE|area'][key] = val
    
    #######################
    key_store = []
    global PREFIX_TMP
    for k, v in COMMON_DATA_MAP['OSPF_NODE|area'].items():
        if k.islower() and k != v:
            key_store.append(k)
        if k != v or '_NODE' not in v:
            key_store.append(v)
    key_store.insert(0, 'area')
    previous_key = key_store[:-1]
    if PREFIX_TMP and 'OSPF_NODE' not in BASE_NODE:
        pre_key = PREFIX_TMP.split('|')[-1]
        if key_store[0].startswith(pre_key):
            if '|' not in PREFIX_TMP:
                PREFIX_TMP = PREFIX_TMP.replace(f'{pre_key}', '')
            else:
                PREFIX_TMP = PREFIX_TMP.replace(f'|{pre_key}', '')
        if PREFIX_TMP != '' and key_store[0] not in PREFIX_TMP:
            key_store[0] = f'{PREFIX_TMP}|{key_store[0]}'
            if len(previous_key) == 0:
                previous_key = [PREFIX_TMP]
            else:
                previous_key[0] = f'{PREFIX_TMP}|{previous_key[0]}'
        if PREFIX_TMP.endswith(f'|{key_store[0]}'):
            key_store[0] = PREFIX_TMP
    
    COMMON_DATA_MAP['OSPF_NODE'] = tuple(key_store)
    PREFIX_TMP = '|'.join(key_store)

    pass


