@frr_config_router_ospf_vrf_no_ospf.group(cls=FRR_AbbreviationGroup, name='rfc1583compatibility', invoke_without_command=True)
def frr_config_router_ospf_vrf_no_ospf_rfc1583compatibility(rfc1583compatibility_='rfc1583compatibility'):
    """Disable the RFC1583Compatibility flag"""
    global COMMON_DATA_MAP
    #ctx = click.get_current_context()
    #config_db = ValidatedConfigDBConnector(db.cfgdb)
    
    data_gen = {}
    name = frr_config_router_ospf_vrf_no_ospf_rfc1583compatibility.name
    data_gen['rfc1583compatibility'] = rfc1583compatibility_='rfc1583compatibility'
    
    if 'OSPF_NODE|no_ospf' not in COMMON_DATA_MAP:
        COMMON_DATA_MAP['OSPF_NODE|no_ospf'] = {}

    for key, val in data_gen.items():
        if key.islower() and key in COMMON_DATA_MAP['OSPF_NODE|no_ospf']:
            key = key.upper()
        COMMON_DATA_MAP['OSPF_NODE|no_ospf'][key] = val
    
    #######################
    key_store = []
    global PREFIX_TMP
    for k, v in COMMON_DATA_MAP['OSPF_NODE|no_ospf'].items():
        if k.islower() and k != v:
            key_store.append(k)
        if k != v or '_NODE' not in v:
            key_store.append(v)
    key_store.insert(0, 'no_ospf')
    previous_key = key_store[:-1]
    if PREFIX_TMP and 'OSPF_NODE' not in BASE_NODE:
        pre_key = PREFIX_TMP.split('|')[-1]
        if key_store[0].startswith(pre_key):
            if '|' not in PREFIX_TMP:
                PREFIX_TMP = PREFIX_TMP.replace(f'{pre_key}', '')
            else:
                PREFIX_TMP = PREFIX_TMP.replace(f'|{pre_key}', '')
        if PREFIX_TMP != '' and key_store[0] not in PREFIX_TMP:
            key_store[0] = f'{PREFIX_TMP}|{key_store[0]}'
            if len(previous_key) == 0:
                previous_key = [PREFIX_TMP]
            else:
                previous_key[0] = f'{PREFIX_TMP}|{previous_key[0]}'
        if PREFIX_TMP.endswith(f'|{key_store[0]}'):
            key_store[0] = PREFIX_TMP
    
    COMMON_DATA_MAP['OSPF_NODE'] = tuple(key_store)
    PREFIX_TMP = '|'.join(key_store)

    pass


